extern void trap(void) __attribute__((noreturn));

void main(void) {
    volatile int x = 1;
    volatile int s = 32;         // shift by 32: C UB (>= int width)
    int y = x << s;               // RV64 sllw: 32 & 0x1f = 0, y = x = 1
    __CPROVER_assert(y == 1, "trap reachable");
}
